1	type Item = { type: string };
2	type Scenario = { steps: Array<{ items: Item[] }> };
3	
4	const PROCESSING_FEE = 5;
5	
6	const PREMIUM_BY_TYPE: Record<string, number> = {
7	  amulet: 71,
8	  staff: 93,
9	  potion: 49,
10	  sword: 115,
11	  rune: 33,
12	};
13	
14	export function runScenario(input: unknown): unknown {
15	  const { steps } = input as Scenario;
16	  const premium = computePremium(steps[0].items);
17	  return { results: [{ premium }] };
18	}
19	
20	function computePremium(items: Item[]): number {
21	  if (items.length === 0) return PROCESSING_FEE;
22	  return PREMIUM_BY_TYPE[items[0].type];
23	}
